- 'first couple of teams' refers to the teams with team_id 1 and 2;
- 'roles' refer to the position names of the players;
- 'team affiliations' mean the team names the players belong to.

sql:
SELECT position_id, COUNT(player_id) AS player_count
FROM player_positions
GROUP BY position_id;

SELECT p.player_id, p.name, p.nationality
FROM players p
JOIN player_injuries pi ON p.player_id = pi.player_id;

SELECT DISTINCT player_id 
FROM match_players
WHERE goals_scored > 5 AND minutes_played > 1500;

